const accordion=document.querySelectorAll(".accordion-menu"),burgerMenu=document.querySelector(".menu-btn"),wrapper=document.querySelector(".wrapper"),menuBox=document.querySelector(".menu-box");for(let e=0;e<accordion.length;e++)accordion[e].addEventListener("click",(function(){const e=this.nextElementSibling;e.style.maxHeight?e.style.maxHeight=null:e.style.maxHeight=e.scrollHeight+"px"}));burgerMenu.addEventListener("click",(function(){menuBox.classList.toggle("active"),wrapper.classList.toggle("active-wrapper"),console.log("hello")}));